{"path":"/home/user/workspace/app/page.tsx","content":"import { connection } from 'next/server'

/**
 * A server component that is rendered for each request rather than being
 * prerendered at build time.
 */
export default async function Home() {
  // `connection()` is Next.js's recommended way to opt out of prerendering
  // when the page needs request-time data but does not need request metadata.
  await connection()

  const timestamp = new Date().toISOString()

  return (
    <main>
      <h1>Current server timestamp</h1>
      <p>{timestamp}</p>
    </main>
  )
}
"}

